// generar_245_tips_portadas_y_signos.js
// CHIQUI Entre Señales — ChiquiTips: portadas honestas + signos compactos
//
// Dos ajustes UX:
//
// 1) PORTADAS (16 tarjetas: sextas de cada grupo × 2 especies) —
//    reescritas para responder "¿qué voy a encontrar aquí?" en vez
//    de decir "Lee los tips de Chiqui..." (el usuario ya está aquí).
//
//    Antes: "¿Sabes reconocer signos de alerta? Lee los tips de
//    Chiqui para saber qué hacer (y qué evitar) ante convulsiones,
//    golpe de calor, intoxicación, accidentes o dificultad para
//    respirar."
//
//    Ahora: "¿Sabes reconocer un signo de alerta? Aprende a reconocer
//    las señales, qué hacer y qué evitar en las situaciones más
//    importantes."
//
//    Todas las portadas comparten esta lógica: título que enmarca,
//    subtítulo con los temas concretos que verás dentro.
//
// 2) SIGNOS DE ALERTA al expandir — mucho más compacto:
//    - Fuera los títulos "HAZ ESTO" y "EVITA" (redundantes con los
//      emojis).
//    - Fuera las barras laterales de color verde y rojo.
//    - Cada línea lleva ✅ (haz) o 🚫 (evita) al inicio. El semáforo
//      se lee EN la línea misma — más natural, ocupa menos espacio.
//    - "Cómo reconocerlo" queda como intro en cursiva, sin etiqueta.
//
//    Ejemplo:
//      Me sacudo sin control y no respondo.
//      ✅ Aleja objetos cercanos
//      ✅ Cronometra el episodio
//      🚫 Sujetarme
//      🚫 Poner algo en mi boca
//
// Solo reescribe components/ChiquiTeCuenta.tsx. No hay SQL.
//
// Uso:
//   node generar_245_tips_portadas_y_signos.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'components/ChiquiTeCuenta.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
